import{_ as r,c as o,o as e,ag as a}from"./chunks/framework.DVUBUV_u.js";const g=JSON.parse('{"title":"Подмена трафика","description":"","frontmatter":{"title":"Подмена трафика"},"headers":[],"relativePath":"network/traffic.md","filePath":"network/traffic.md"}'),l={name:"network/traffic.md"};function n(i,t,s,d,h,p){return e(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="breakpoints-и-mock-response" tabindex="-1">Breakpoints и Mock response <a class="header-anchor" href="#breakpoints-и-mock-response" aria-label="Permalink to &quot;Breakpoints и Mock response&quot;">​</a></h1><p>Во вкладке <strong>Network</strong> и в разделе <strong>Options → Network</strong> доступны два механизма перехвата запросов:</p><ul><li><strong>Breakpoint</strong> — остановка запроса <strong>до отправки в сеть</strong> с возможностью изменить его параметры и затем продолжить выполнение;</li><li><strong>Mock response</strong> — возврат подготовленного ответа <strong>без обращения к серверу</strong>.</li></ul><p>Оба механизма работают только для запросов, проходящих через <strong><code>fetch</code></strong> и <strong><code>XMLHttpRequest</code></strong> внутри текущей страницы.</p><p>Базовые ограничения перехвата (контекст страницы, CORS, scope перехвата и т.д.) описаны в <a href="/docs/network/general.html">Работа с запросами</a>.</p><hr><h2 id="breakpoints" tabindex="-1">Breakpoints <a class="header-anchor" href="#breakpoints" aria-label="Permalink to &quot;Breakpoints&quot;">​</a></h2><h3 id="назначение" tabindex="-1">Назначение <a class="header-anchor" href="#назначение" aria-label="Permalink to &quot;Назначение&quot;">​</a></h3><p>Breakpoint позволяет остановить исходящий запрос <strong>до его отправки</strong>.</p><p>Когда URL и метод совпадают с правилом:</p><ul><li>выполнение запроса приостанавливается;</li><li>в панели становится доступно редактирование параметров;</li><li>после подтверждения запрос отправляется уже с изменениями;</li><li>либо выполнение можно отменить.</li></ul><p>Фактически перехват происходит после того, как приложение сформировало запрос, но до вызова нативной отправки.</p><h3 id="что-можно-изменить" tabindex="-1">Что можно изменить <a class="header-anchor" href="#что-можно-изменить" aria-label="Permalink to &quot;Что можно изменить&quot;">​</a></h3><p>До продолжения доступны для редактирования:</p><ul><li>HTTP-метод;</li><li>URL (схема, хост, путь, query);</li><li>заголовки;</li><li>тело запроса.</li></ul><p>После <strong>Apply</strong> запрос отправляется в сеть уже в изменённом виде.</p><h3 id="где-настраивать" tabindex="-1">Где настраивать <a class="header-anchor" href="#где-настраивать" aria-label="Permalink to &quot;Где настраивать&quot;">​</a></h3><ul><li><strong>Network</strong> — создание и изменение breakpoint на основе конкретного запроса.</li><li><strong>Options → Network → Breakpoints</strong> — изменение существующего списка правил;</li></ul><h3 id="особенности-работы" tabindex="-1">Особенности работы <a class="header-anchor" href="#особенности-работы" aria-label="Permalink to &quot;Особенности работы&quot;">​</a></h3><p>При совпадении запроса с активным правилом breakpoint интерфейс автоматически переводится в режим редактирования:</p><ul><li>открывается карточка сработавшего breakpoint;</li><li>при необходимости выполняется переход во вкладку <strong>Network</strong>;</li><li>свернутый iframe инспектора автоматически разворачивается.</li></ul><p>До подтверждения или отмены выполнение запроса остаётся приостановленным.</p><h2 id="mock-response" tabindex="-1">Mock response <a class="header-anchor" href="#mock-response" aria-label="Permalink to &quot;Mock response&quot;">​</a></h2><h3 id="назначение-1" tabindex="-1">Назначение <a class="header-anchor" href="#назначение-1" aria-label="Permalink to &quot;Назначение&quot;">​</a></h3><p>Mock response полностью заменяет сетевой запрос локальным ответом.</p><p>При совпадении правила:</p><ul><li>запрос в сеть не отправляется;</li><li>создаётся синтетический ответ;</li><li>страница получает его как обычный HTTP ответ.</li></ul><h3 id="что-задается-в-mock" tabindex="-1">Что задаётся в mock <a class="header-anchor" href="#что-задается-в-mock" aria-label="Permalink to &quot;Что задаётся в mock&quot;">​</a></h3><p>Правило может содержать:</p><ul><li><strong>status</strong> и <strong>statusText</strong>;</li><li><strong>headers</strong>;</li><li><strong>body</strong>;</li><li><strong>delay</strong> перед возвратом ответа.</li></ul><h3 id="где-настраивать-1" tabindex="-1">Где настраивать <a class="header-anchor" href="#где-настраивать-1" aria-label="Permalink to &quot;Где настраивать&quot;">​</a></h3><ul><li><strong>Network</strong> — создание и изменение mock на основе конкретного запроса.</li><li><strong>Options → Network → Breakpoints</strong> — изменение существующего списка правил;</li></ul><h3 id="особенности-работы-1" tabindex="-1">Особенности работы <a class="header-anchor" href="#особенности-работы-1" aria-label="Permalink to &quot;Особенности работы&quot;">​</a></h3><p>Если сработал mock:</p><ul><li>реальный запрос на сервер не выполняется;</li><li>breakpoint для этого вызова уже не применяется.</li></ul><p>Порядок проверки:</p><ol><li>сначала mock;</li><li>если mock не подошёл — breakpoint;</li><li>затем обычный сетевой запрос.</li></ol><p>То есть mock имеет приоритет над breakpoint.</p><hr><h2 id="сравнение-breakpoint-и-mock" tabindex="-1">Сравнение breakpoint и mock <a class="header-anchor" href="#сравнение-breakpoint-и-mock" aria-label="Permalink to &quot;Сравнение breakpoint и mock&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Механизм</th><th>Отправка в сеть</th><th>Можно изменить запрос</th><th>Можно изменить ответ</th></tr></thead><tbody><tr><td>Breakpoint</td><td>Да</td><td>Да</td><td>Нет</td></tr><tr><td>Mock response</td><td>Нет</td><td>Нет</td><td>Да</td></tr></tbody></table><hr><h2 id="ограничения" tabindex="-1">Ограничения <a class="header-anchor" href="#ограничения" aria-label="Permalink to &quot;Ограничения&quot;">​</a></h2><p>Оба механизма работают только для запросов, выполненных через:</p><ul><li><strong>fetch</strong></li><li><strong>XMLHttpRequest</strong></li></ul><p>Не перехватываются:</p><ul><li>загрузка ресурсов через <code>&lt;img&gt;</code>, <code>&lt;script&gt;</code>, <code>&lt;link&gt;</code>;</li><li>Service Worker вне текущего interception layer;</li><li>нативные сетевые вызовы браузера вне JS-контекста страницы.</li></ul><p>Запросы <strong>OPTIONS (preflight)</strong> также не участвуют в перехвате.</p><hr><h2 id="сравнение-с-charles-proxy" tabindex="-1">Сравнение с Charles Proxy <a class="header-anchor" href="#сравнение-с-charles-proxy" aria-label="Permalink to &quot;Сравнение с Charles Proxy&quot;">​</a></h2><p><strong>Charles</strong> (и аналогичные <strong>системные / внешние прокси</strong>: Fiddler, mitmproxy и др.) встаёт <strong>между клиентом и сервером</strong> на уровне ОС или отдельного приложения:</p><ul><li>видит трафик <strong>не только из браузера</strong>, но и из мобильных приложений, CLI, других программ (если направить их через прокси);</li><li>для <strong>HTTPS</strong> обычно нужна установка доверенного сертификата и <strong>SSL Proxying</strong> — расшифровка TLS на прокси;</li><li><strong>Breakpoint</strong> и <strong>Map Local / Remote</strong> применяются ко <strong>всем</strong> подходящим запросам в этом канале.</li></ul><p><strong>Vue Inspector</strong> работает <strong>внутри вкладки браузера</strong>: подменяются глобальные <strong><code>fetch</code></strong> и <strong><code>XMLHttpRequest</code></strong>.</p><table tabindex="0"><thead><tr><th>Аспект</th><th>Charles (типично)</th><th>Vue Inspector</th></tr></thead><tbody><tr><td>Уровень</td><td>Прокси / вне процесса браузера</td><td>JavaScript на странице</td></tr><tr><td>Охват</td><td>Много клиентов, весь HTTP(S) через прокси</td><td>Только этот документ: вызовы <strong>fetch</strong> и <strong>XHR</strong></td></tr><tr><td>HTTPS</td><td>Свой корень доверия, разбор TLS</td><td>Без отдельного «взлома» TLS — приложение и так отдаёт ответы в свой JS</td></tr><tr><td>Service Worker, нативные запросы</td><td>Можно перехватывать на пути</td><td>Не перехватываются этим механизмом</td></tr><tr><td>Удобство для SPA в браузере</td><td>Нужна настройка прокси и сертификатов</td><td>Включил правила в инспекторе — работает на текущем сайте</td></tr></tbody></table><p>Итог: по <strong>смыслу</strong> Breakpoint и Mock в Inspector близки к Charles (<strong>остановить / подменить ответ</strong>), но по <strong>месту действия</strong> это не сетевой прокси, а <strong>инструмент разработчика веб-страницы</strong> на том же origin-жизненном цикле, что и ваше Vue‑приложение.</p><h2 id="см-также" tabindex="-1">См. также <a class="header-anchor" href="#см-также" aria-label="Permalink to &quot;См. также&quot;">​</a></h2><ul><li><a href="/docs/network/general.html">Работа с запросами</a></li><li><a href="/docs/network/export.html">Экспорт коллекций</a></li></ul>',57)])])}const k=r(l,[["render",n]]);export{g as __pageData,k as default};
